import scala.collection.mutable.{Queue, HashMap, ListBuffer}

def solve(nums: Array[Long]): Long = {
  val n = nums.length
  if (n == 0) return 0L
  if (n == 1) return 0L

  val maxNum = 1000000
  val spf = Array.fill(maxNum + 1)(0)
  for (i <- 2 to maxNum) {
    if (spf(i) == 0) {
      spf(i) = i
      for (j <- i * 2 to maxNum by i) {
        if (spf(j) == 0) spf(j) = i
      }
    }
  }

  val primeToIndices = HashMap[Int, ListBuffer[Int]]()
  for (i <- 0 until n) {
    val x = nums(i).toInt
    if (x == 1) continue
    var num = x
    val factors = scala.collection.mutable.HashSet[Int]()
    while (num > 1) {
      val p = spf(num)
      factors += p
      while (num % p == 0) {
        num /= p
      }
    }
    for (p <- factors) {
      primeToIndices.getOrElseUpdate(p, ListBuffer[Int]()).append(i)
    }
  }

  val visited = Array.fill(n)(-1L)
  val queue = Queue[(Int, Long)]()
  queue.enqueue((0, 0L))
  visited(0) = 0

  while (queue.nonEmpty) {
    val (current, steps) = queue.dequeue()
    if (current == n - 1) return steps
    for (dir <- Array(-1, 1)) {
      val next = current + dir
      if (0 <= next && next < n && visited(next) == -1) {
        visited(next) = steps + 1
        queue.enqueue((next, steps + 1))
      }
    }
    val x = nums(current).toInt
    if (x > 1 && spf(x) == x) {
      val p = x
      val indices = primeToIndices.get(p)
      if (indices.isDefined) {
        for (j <- indices.get) {
          if (j != current && visited(j) == -1) {
            visited(j) = steps + 1
            queue.enqueue((j, steps + 1))
          }
        }
      }
    }
  }

  -1L
}
